'use strict';

// MODULES //

var path = require( 'path' );
var tape = require( 'tape' );
var remark = require( 'remark' );
var readFileSync = require( '@stdlib/fs/read-file' ).sync;
var expectedSections = require( './../lib' );


// VARIABLES //

var TEST_FIXTURES = path.join( __dirname, 'fixtures' );
var DEFAULT_SCHEMA = {
	'root': {
		'required': [ 'usage', 'examples', 'links' ],
		'optional': [ 'intro', 'notes', 'c', 'references', 'related' ]
	},
	'c': {
		'required': [ 'usage', 'examples' ],
		'optional': [ 'intro', 'notes' ]
	}
};
var CUSTOM_SCHEMA = {
	'root': {
		'required': [ 'usage', 'examples', 'links', 'related' ],
		'optional': [ 'intro', 'notes', 'c', 'references' ]
	}
};


// FUNCTIONS //

function fixture( name ) {
	var text = readFileSync( path.join( TEST_FIXTURES, name ), 'utf8' );
	return text.toString();
}

function lint( text, options, clbk ) {
	remark().use( expectedSections, options ).process( text, clbk );
}


// TESTS //

tape( 'main export is a function', function test( t ) {
	t.ok( true, __filename );
	t.strictEqual( typeof expectedSections, 'function', 'main export is a function' );
	t.end();
});

tape( 'validates valid_complete.md.txt with default schema', function test( t ) {
	var opts = {
		'schema': DEFAULT_SCHEMA
	};

	lint( fixture( 'valid_complete.md.txt' ), opts, done );

	function done( err, file ) {
		if ( err ) {
			t.fail( err.message );
		}
		t.strictEqual( file.messages.length, 0, 'has no errors for valid fixture with all sections' );
		t.end();
	}
});

tape( 'validates valid_memoize.md.txt', function test( t ) {
	var opts = {
		'schema': DEFAULT_SCHEMA
	};

	lint( fixture( 'valid_memoize.md.txt' ), opts, done );

	function done( err, file ) {
		if ( err ) {
			t.fail( err.message );
		}
		t.strictEqual( file.messages.length, 0, 'has no errors for memoize README fixture' );
		t.end();
	}
});

tape( 'validates valid_asin.md.txt with C section', function test( t ) {
	var opts = {
		'schema': DEFAULT_SCHEMA
	};

	lint( fixture( 'valid_asin.md.txt' ), opts, done );

	function done( err, file ) {
		if ( err ) {
			t.fail( err.message );
		}
		t.strictEqual( file.messages.length, 0, 'has no errors for asin README fixture with C section' );
		t.end();
	}
});

tape( 'detects missing C usage section in invalid_asin.md.txt', function test( t ) {
	var opts = {
		'schema': DEFAULT_SCHEMA
	};

	lint( fixture( 'invalid_asin.md.txt' ), opts, done );

	function done( err, file ) {
		if ( err ) {
			t.fail( err.message );
		}
		t.strictEqual( file.messages.length, 1, 'has one error for invalid asin fixture' );
		t.strictEqual( file.messages[0].reason.includes('Missing required sections in "c" section: usage'), true, 'error identifies the missing C usage section' );
		t.end();
	}
});

tape( 'reports error for missing required root sections', function test( t ) {
	var opts = {
		'schema': DEFAULT_SCHEMA
	};

	lint( fixture( 'missing_required_root.md.txt' ), opts, function done( err, file ) {
		if ( err ) {
			t.fail( err.message );
		}
		t.strictEqual( file.messages.length, 1, 'has one error for fixture missing a required root section' );
		t.strictEqual( file.messages[0].reason.includes('Missing required root-level sections: usage'), true, 'error identifies the missing section' );
		t.end();
	});
});

tape( 'reports error for incomplete C section', function test( t ) {
	var opts = {
		'schema': DEFAULT_SCHEMA
	};

	lint( fixture( 'incomplete_c.md.txt' ), opts, done );

	function done( err, file ) {
		if ( err ) {
			t.fail( err.message );
		}
		t.strictEqual( file.messages.length, 1, 'has one error for fixture with an incomplete C section' );
		t.strictEqual( file.messages[0].reason.includes('Missing required sections in "c" section: usage, examples'), true, 'error identifies the missing C sections' );
		t.end();
	}
});

tape( 'validates valid_complete.md.txt with custom schema', function test( t ) {
	var opts = {
		'schema': CUSTOM_SCHEMA
	};

	lint( fixture( 'valid_complete.md.txt' ), opts, done );

	function done( err, file ) {
		if ( err ) {
			t.fail( err.message );
		}
		t.strictEqual( file.messages.length, 0, 'has no errors for valid fixture with custom schema' );
		t.end();
	}
});

tape( 'reports correct errors with custom schema', function test( t ) {
	var opts = {
		'schema': CUSTOM_SCHEMA
	};

	lint( fixture( 'missing_required_root.md.txt' ), opts, done );

	function done( err, file ) {
		if ( err ) {
			t.fail( err.message );
		}
		t.strictEqual( file.messages.length, 1, 'has correct number of errors with custom schema' );
		t.strictEqual( file.messages[0].reason.includes('usage') && file.messages[0].reason.includes('related'), true, 'error identifies both missing sections' );
		t.end();
	}
});
